function openModal(){
	var gm = new GlideModal('x_153465_discovert_cancel_prompt');
	gm.setTitle('Cancel ' + g_form.getValue('number') + "?");
	gm.setPreference("sysparm_taskSysId", g_form.getUniqueValue());
	gm.setPreference("sysparm_taskOwner", g_form.getValue('u_task_requester'));
	gm.setPreference("sysparm_numberOfSubTasks", g_form.getValue('u_last_unassigned_date'));
	gm.setWidth(550);
	gm.render();
}


